select

from bio_task_dtl_tb
where
task_status !='0'
and id = #{id,jdbcType=INTEGER}
and task_type_code=#{taskTypeCode,jdbcType=VARCHAR}

and task_num=#{taskNum,jdbcType=VARCHAR}
and task_status=#{taskStatus,jdbcType=VARCHAR}
and task_desc  like  CONCAT('%',#{taskDesc,jdbcType=VARCHAR},'%')
and apply_user_id=#{applyUserId,jdbcType=NUMERIC}
and apply_user_name=#{applyUserName,jdbcType=VARCHAR}
and apply_time=#{applyTime,jdbcType=TIMESTAMP}

and date_format(create_time,'%Y-%m-%d') =  #{applyDate,jdbcType=VARCHAR}

and update_time=#{updateTime,jdbcType=TIMESTAMP}
and task_form=#{taskForm,jdbcType=VARCHAR}
and task_type_name=#{taskTypeName,jdbcType=VARCHAR}
and instance_id=#{instanceId,jdbcType=NUMERIC}
and ref_task_num=#{refTaskNum,jdbcType=VARCHAR}
and task_category=#{taskCategory,jdbcType=VARCHAR}
order by update_time desc

